{"slots": [{"id": "arr", "type": "array", "label": "Sorted Array"}], "inputs": [{"label": "Target", "default": "23"}], "code": "class Playground {
    async run(inputs) {
        const target = parseInt(inputs.Target);
        const data = [2, 5, 8, 12, 16, 23, 38, 56, 72, 91];
        await this.arr.init(data);

        let low = 0;
        let high = data.length - 1;

        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            this.log(`Checking range [${low}, ${high}], middle index: ${mid}`);

            // Clear previous and highlight search range and mid
            this.arr.highlightRange(0, data.length - 1, null);
            this.arr.highlightRange(low, high, 'rgba(34, 211, 238, 0.2)');
            this.arr.highlight(mid, '#f59e0b'); // Amber for checking
            await this.await();

            if (data[mid] === target) {
                this.arr.highlight(mid, '#10b981'); // Emerald for success
                this.log(`Target ${target} found at index ${mid}!`);
                return;
            }

            if (data[mid] < target) {
                this.log(`${data[mid]} < ${target}. Discarding left half.`);
                low = mid + 1;
            } else {
                this.log(`${data[mid]} > ${target}. Discarding right half.`);
                high = mid - 1;
            }
            await this.await();
        }

        this.log(`Target ${target} was not found in the array.`);
    }
}"}

